INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (62,'wc-admin-new-sales-record','info','en_US','New sales record!','Woohoo, January 17th was your record day for sales! Net sales was 194.50$ beating the previous record of 83.50$ set on January 16th.','{\"old_record_date\":\"2025-01-16\",\"old_record_amt\":83.5,\"new_record_date\":\"2025-01-17\",\"new_record_amt\":194.5}','actioned','woocommerce-admin','2025-01-18 11:35:05',NULL,0,'plain','',0,1,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (63,'affirm_promo_Q1_2025','marketing','en_US','Save up to 50% on merchant fees with Affirm','Kickstart the year with buy now, pay later and get merchant rates as low as 2.9% + 30� per transaction for 30 days. Download the extension and complete your application from your WooCommerce dashboard by February 19, 2025 to claim the offer. Terms and conditions apply.','{}','pending','woocommerce.com','2025-01-21 10:28:33',NULL,0,'plain','',0,0,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (64,'wc-admin-usage-tracking-opt-in','info','en_US','Help WooCommerce improve with usage tracking','Gathering usage data allows us to improve WooCommerce. Your store will be considered as we evaluate new features, judge the quality of an update, or determine if an improvement makes sense. You can always visit the <a href=\"https://antiviruspointorgdomainonly.wpcomstaging.com/wp-admin/admin.php?page=wc-settings&#038;tab=advanced&#038;section=woocommerce_com\" target=\"_blank\">Settings</a> and choose to stop sharing data. <a href=\"https://woocommerce.com/usage-tracking?utm_medium=product\" target=\"_blank\">Read more</a> about what data we collect.','{}','unactioned','woocommerce-admin','2025-01-23 10:29:52',NULL,0,'plain','',0,0,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (65,'wc-admin-woocommerce-payments','marketing','en_US','Try the new way to get paid','Securely accept credit and debit cards on your site. Manage transactions without leaving your WordPress dashboard. Only with <strong>WooPayments</strong>.<br><br>By clicking \"Get started\", you agree to our <a href=\"https://wordpress.com/tos/\" target=\"_blank\">Terms of Service</a>','{}','unactioned','woocommerce-admin','2025-01-23 10:29:52',NULL,0,'plain','',0,0,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (66,'new-woo-brand-announcement-feb4-2025','marketing','en_US','Meet the new Woo','WooCommerce has a new look, but underneath, we�re still the same customizable, open-source ecommerce platform you know and love. Plus, we�ve got some major improvements to our platform and product on the way.','{}','pending','woocommerce.com','2025-02-05 10:30:24',NULL,0,'plain','',0,0,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (67,'wc-update-db-reminder','update','en_US','WooCommerce database update required','WooCommerce has been updated! To keep things running smoothly, we have to update your database to the newest version. The database update process runs in the background and may take a little while, so please be patient. Advanced users can alternatively update via <a href=\"https://github.com/woocommerce/woocommerce/wiki/Upgrading-the-database-using-WP-CLI\">WP CLI</a>.','{}','actioned','woocommerce-core','2025-02-05 10:44:30',NULL,0,'plain','',1,0,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (68,'paypal_bnpl_au_promo_Q1_2025','marketing','en_US','Australian shoppers can Pay in 4 with PayPal','Enable Pay in 4 messaging to let Australian customers know that they can pay over time while you get paid up front and in full. Pay in 4 is included in PayPal Payments at no additional cost. Eligible buyers can pay in four interest-free payments for purchases of $30 to $2,000 AUD. Terms apply.','{}','pending','woocommerce.com','2025-02-12 10:30:10',NULL,0,'plain','',0,0,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (73,'wc-admin-orders-milestone','info','en_US','Congratulations on processing 10 orders!','You\'ve hit the 10 orders milestone! Look at you go. Browse some WooCommerce success stories for inspiration.','{\"current_milestone\":10}','actioned','woocommerce-admin','2025-02-14 11:28:44',NULL,0,'plain','',0,1,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (75,'wc-admin-real-time-order-alerts','info','en_US','Get real-time order alerts anywhere','Get notifications about store activity, including new orders and product reviews directly on your mobile devices with the Woo app.','{}','unactioned','woocommerce-admin','2025-06-18 10:30:31',NULL,0,'plain','',0,1,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (76,'paypal-braintree-sdk-depreciation-2025-02-20','update','en_US','Update required for your PayPal Braintree extension','To continue securely accepting payments, you must update your PayPal Braintree extension to version 3.2.4 or newer before June 30, 2025. Your current extension version will not support payment processing after this date due to an SSL certificate update.','{}','pending','woocommerce.com','2025-06-18 10:30:32',NULL,0,'plain','',0,0,'info');
INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (77,'uk-vat-notice-2025-04-30','warning','en_US','UK VAT numbers are no longer supported','Due to recent HM Revenue &amp; Customs (HMRC) VAT API changes, your EU VAT Number for WooCommerce extension can no longer validate UK VAT numbers. HMRC now requires merchants to register an API key, which this extension does not currently support. We recommend EU/UK VAT Validation Manager for WooCommerce as a replacement','{}','pending','woocommerce.com','2025-06-18 10:30:32',NULL,0,'plain','',0,0,'info');
