INSERT INTO `fqsi_wc_admin_notes` (`note_id`, `name`, `type`, `locale`, `title`, `content`, `content_data`, `status`, `source`, `date_created`, `date_reminder`, `is_snoozable`, `layout`, `image`, `is_deleted`, `is_read`, `icon`) VALUES (152,'usps-hazmat-Wcs-jul','marketing','en_US','USPS HAZMAT enforcement starts July 12','If you ship hazardous materials — lithium batteries, aerosols, perfume, paint — USPS adds noncompliance fees starting July 12. WooCommerce Shipping labels stay the same. Declare HAZMAT accurately, remove old HAZMAT marks from reused boxes, and place labels on the address side.','{}','pending','woocommerce.com','2026-07-15 10:31:22',NULL,0,'plain','',0,0,'info');
